def apply_preset_theme(tenant_id, theme_name):
    """Applies a preset theme to a tenant."""
    if theme_name not in PRESET_THEMES:
        print(f"Unknown theme: {theme_name}")
        print(f"Available: {', '.join(PRESET_THEMES.keys())}")
        return False

    manager = BrandingManager()
    manager.set_branding(tenant_id, PRESET_THEMES[theme_name])
    print(f"  Theme '{theme_name}' applied to tenant {tenant_id}")
    return True


# ── CLI ───────────────────────────────────────────────────────
if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(
        description="LLM Scanner — Custom Branding"
    )
    subparsers = parser.add_subparsers(dest="command")

    # Set branding
    p_set = subparsers.add_parser("set")
    p_set.add_argument("tenant_id")
    p_set.add_argument("--company",   default="My Company")
    p_set.add_argument("--primary",   default="#1F3864")
    p_set.add_argument("--secondary", default="#2E75B6")
    p_set.add_argument("--footer",    default="Confidential Report")
    p_set.add_argument("--title",     default="AI Security Report")
    p_set.add_argument("--no-badge",  action="store_true")

    # Preview
    p_prev = subparsers.add_parser("preview")
    p_prev.add_argument("tenant_id")

    # Apply theme
    p_theme = subparsers.add_parser("theme")
    p_theme.add_argument("tenant_id")
    p_theme.add_argument("theme_name",
        choices=list(PRESET_THEMES.keys()))

    # Reset
    p_reset = subparsers.add_parser("reset")
    p_reset.add_argument("tenant_id")

    # Generate branded report
    p_gen = subparsers.add_parser("report")
    p_gen.add_argument("tenant_id")
    p_gen.add_argument("--input",  required=True)
    p_gen.add_argument("--output", default=None)
    p_gen.add_argument("--target", default="AI Application")

    # List themes
    subparsers.add_parser("themes")

    args    = parser.parse_args()
    manager = BrandingManager()

    if args.command == "set":
        manager.set_branding(args.tenant_id, {
            "company_name"         : args.company,
            "primary_color"        : args.primary,
            "secondary_color"      : args.secondary,
            "footer_text"          : args.footer,
            "report_title"         : args.title,
            "show_llmscanner_badge": not args.no_badge
        })

    elif args.command == "preview":
        manager.preview_branding(args.tenant_id)

    elif args.command == "theme":
        apply_preset_theme(args.tenant_id, args.theme_name)

    elif args.command == "reset":
        manager.reset_branding(args.tenant_id)

    elif args.command == "report":
        output = args.output or \
                 args.input.replace(".json", "_branded.pdf")
        gen = BrandedReportGenerator(tenant_id=args.tenant_id)
        gen.generate(args.input, output, args.target)

    elif args.command == "themes":
        print("\n  Available Themes :")
        for name, theme in PRESET_THEMES.items():
            print(f"\n  {name}")
            print(f"    Primary   : {theme['primary_color']}")
            print(f"    Secondary : {theme['secondary_color']}")
            print(f"    Title     : {theme['report_title']}")

    else:
        parser.print_help()
        